using System.Collections;
using UnityEngine;

// Ações do Sistema de Pistas/Rumores (Diário) — aparecem automaticamente no
// "+ Adicionar Ação" de qualquer NpcController (incluindo objectos genéricos
// reutilizados como interactivos, Ponto 9 da especificação).

/// <summary>
/// Mostra uma imagem em ecrã inteiro (fora do balão de diálogo, fundo
/// escurecido), pausa o diálogo e o jogo enquanto estiver aberta, e fecha com
/// o botão normal de Confirmar/Interagir (teclado ou comando) — ver
/// FullscreenImageUI. Depois de confirmada, a ação termina e o diálogo
/// continua normalmente.
///
/// Se "saveAsClue" estiver activo, a pista correspondente
/// ("mission.clues[clueId]") fica marcada como obtida (JournalManager) e
/// passa a aparecer, permanentemente, na sub-secção "Pistas" dessa missão no
/// Diário — onde pode ser reaberta em ecrã inteiro a qualquer momento.
/// </summary>
[System.Serializable]
public class Action_ShowFullscreenImage : NpcAction
{
    [Header("Imagem em Ecrã Inteiro")]
    public Sprite image;

    [Tooltip("Título opcional mostrado por cima da imagem.")]
    public string title;

    [TextArea]
    [Tooltip("Descrição/texto opcional mostrado junto à imagem.")]
    public string description;

    [Header("Guardar como Pista (Diário)")]
    [Tooltip("Se activo, ao confirmar a imagem fica guardada na sub-secção \"Pistas\" da missão indicada, reabrível a partir do Diário.")]
    public bool saveAsClue;

    [Tooltip("Missão a que esta pista pertence (necessário se \"saveAsClue\" estiver activo). Tem de ter uma entrada correspondente em \"mission.clues\" com o mesmo \"clueId\".")]
    public MissionData mission;

    [Tooltip("Identificador da pista dentro de \"mission.clues\" (necessário se \"saveAsClue\" estiver activo).")]
    public string clueId;

    public override IEnumerator Execute(NpcController npc)
    {
        if (FullscreenImageUI.Instance != null)
            yield return FullscreenImageUI.Instance.Show(image, title, description);

        if (saveAsClue && mission != null && !string.IsNullOrEmpty(clueId))
            JournalManager.Instance?.GiveClue(mission, clueId);
    }
}

/// <summary>
/// Regista um Rumor (RumorData) — informação mais indirecta, sem iniciar
/// nenhuma missão — na secção global "Rumores" do Diário (JournalManager).
/// Um rumor pode ter texto e/ou imagem; nunca desaparece do Diário depois de
/// ouvido (ver Action_MarkRumorFound para o ícone de "Check").
///
/// Se "showImageNow" estiver activo e o rumor tiver imagem, esta é mostrada em
/// ecrã inteiro de imediato (ex: o NPC mostra uma fotografia enquanto fala) —
/// a imagem fica sempre disponível a partir do Diário, mesmo sem isto
/// activado.
/// </summary>
[System.Serializable]
public class Action_AddRumor : NpcAction
{
    [Tooltip("Rumor a registar na secção \"Rumores\" do Diário (texto e/ou imagem).")]
    public RumorData rumor;

    [Tooltip("Se activo e o rumor tiver imagem, mostra-a em ecrã inteiro de imediato.")]
    public bool showImageNow;

    public override IEnumerator Execute(NpcController npc)
    {
        if (rumor == null) yield break;

        if (showImageNow && rumor.image != null && FullscreenImageUI.Instance != null)
            yield return FullscreenImageUI.Instance.Show(rumor.image, rumor.title, rumor.text);

        JournalManager.Instance?.AddRumor(rumor);
    }
}

/// <summary>
/// Marca um Rumor (RumorData) já ouvido como "encontrado" — mostra um ícone de
/// "Check" junto a ele na secção "Rumores" do Diário, sem o remover da lista
/// (ver Condition_RumorFound).
/// </summary>
[System.Serializable]
public class Action_MarkRumorFound : NpcAction
{
    [Tooltip("Rumor a marcar como \"encontrado\".")]
    public RumorData rumor;

    public override IEnumerator Execute(NpcController npc)
    {
        JournalManager.Instance?.MarkRumorFound(rumor);
        yield break;
    }
}
